import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is the dew point?", a: "The dew point is the temperature at which air must be cooled (at constant pressure and water vapor content) to become saturated with water vapor. Below this temperature, water vapor condenses into liquid water - forming dew on surfaces, fog in the air, or frost in cold conditions." },
  { q: "What dew point temperature is comfortable?", a: "Below 55 F (13 C) is very comfortable and dry. 55-60 F (13-16 C) is comfortable with slight humidity. 60-65 F (16-18 C) feels noticeably humid. 65-70 F (18-21 C) feels sticky and uncomfortable. Above 70 F (21 C) feels oppressively humid. Most people feel best with dew points in the 50s." },
  { q: "How is dew point different from relative humidity?", a: "Relative humidity (RH) is a percentage showing how close air is to saturation at its current temperature. It changes with temperature even when the moisture content stays constant. Dew point is an absolute measure of atmospheric moisture - it doesn't change unless the actual water vapor content changes. Meteorologists prefer dew point because it directly describes how muggy it feels." },
  { q: "Why does dew form on grass overnight?", a: "At night, the ground cools faster than the surrounding air through radiative cooling. When surface temperatures drop below the dew point of the air, water vapor from the air condenses onto those cooler surfaces as liquid water - forming dew. Heavy dew is common on clear, calm nights when radiative cooling is strongest." },
  { q: "What is the Magnus formula used for dew point?", a: "The Magnus formula (also called the August-Roche-Magnus approximation) calculates dew point from temperature and relative humidity: Td = (b x alpha) / (a - alpha), where alpha = (a x T / (b + T)) + ln(RH/100). Constants a = 17.27 and b = 237.7. It is accurate to about 0.4 C between 0 C and 60 C." },
  { q: "What is the relationship between dew point and fog?", a: "Fog forms when the air temperature at ground level reaches the dew point and relative humidity hits 100%. The air becomes saturated and microscopic water droplets form in suspension. Radiation fog forms overnight on clear nights; advection fog forms when warm moist air moves over cooler surfaces." },
  { q: "Can dew point be higher than the air temperature?", a: "No - by definition, the dew point cannot exceed the air temperature. When dew point equals air temperature, relative humidity is 100% and the air is saturated. Any further cooling would cause condensation (fog, clouds, dew). This is why forecasters watch the temperature-dew point spread closely." },
  { q: "How does dew point affect outdoor comfort during exercise?", a: "At dew points above 65 F, sweat evaporates poorly because the air is already nearly saturated with moisture. This impairs the body's main cooling mechanism. Exercise performance declines significantly above 65 F dew point, and heat illness risk increases sharply above 70 F. Marathon runners aim to race when dew points are below 55 F for optimal conditions." },
];

const COMFORT_SCALE = [
  ["< 10 C (50 F)", "Very Dry", "Desert-like, possible dry skin"],
  ["10-13 C (50-55 F)", "Comfortable", "Ideal - most people prefer this"],
  ["13-16 C (55-60 F)", "Slightly Humid", "Noticeable but still comfortable"],
  ["16-18 C (60-65 F)", "Humid", "Muggy feeling, slightly sticky"],
  ["18-21 C (65-70 F)", "Very Humid", "Uncomfortable, heavy sweating"],
  ["> 21 C (70 F)", "Oppressive", "Heat illness risk, sweat will not evaporate well"],
];

export default function DewPointCalculator() {
  const [tempC, setTempC] = useState(25);
  const [humidity, setHumidity] = useState(65);

  const a = 17.27; const b = 237.7;
  const alpha = (a * tempC / (b + tempC)) + Math.log(humidity / 100);
  const dewC = (b * alpha) / (a - alpha);
  const dewF = dewC * 9/5 + 32;
  const tempF = tempC * 9/5 + 32;

  const comfort = dewC < 10 ? "Very Dry" : dewC < 13 ? "Comfortable" : dewC < 16 ? "Slightly Humid" : dewC < 18 ? "Humid" : dewC < 21 ? "Very Humid" : "Oppressively Humid";
  const color = dewC < 13 ? "from-sky-500 to-sky-700" : dewC < 16 ? "from-green-500 to-green-700" : dewC < 18 ? "from-yellow-500 to-yellow-700" : "from-orange-500 to-orange-700";

  const humidityRows = [30, 40, 50, 60, 70, 80, 90, 100];

  return (
    <>
      <SEOHead
        title="Free Dew Point Calculator Online - Calculate Dew Point Temperature Instantly | CalcHive"
        description="Free online dew point calculator. Calculate the dew point temperature from air temperature and relative humidity instantly. 100% free for everyone, meteorologists and students, no signup required."
        canonical="/dew-point-calculator"
        keywords="free dew point calculator, dew point calculator online free, calculate dew point free, air temperature humidity dew point calculator free, weather dew point tool free"
        category="Weather Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-purple-600 dark:text-purple-400 bg-purple-50 dark:bg-purple-950/50 px-3 py-1 rounded-full mb-4 inline-block">Weather</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Dew Point Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free dew point calculator to calculate dew point free from air temperature and relative humidity. This dew point calculator online free also works as an air temperature humidity dew point calculator free and weather dew point tool free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="temp" label="Air Temperature (C)" value={tempC} min={-20} max={50} step={0.5} onChange={setTempC} format={v => `${v} C (${(v*9/5+32).toFixed(1)} F)`} testId="input-temp" />
            <SliderInput id="humidity" label="Relative Humidity (%)" value={humidity} min={1} max={100} step={1} onChange={setHumidity} format={v => `${v}%`} testId="input-humidity" />
          </div>
          <motion.div key={`${tempC}-${humidity}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${color} rounded-2xl p-6 mb-4 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Dew Point</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-dewpoint">{dewC.toFixed(1)} C</p>
              <p className="text-white/70 text-sm mt-1">{dewF.toFixed(1)} F - {comfort}</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Air Temp", value: `${tempC} C / ${tempF.toFixed(1)} F` },
                { label: "Relative Humidity", value: `${humidity}%` },
                { label: "Comfort Level", value: comfort },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-sm font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Dew Point Temperature for Free</h2>
          <p className="text-muted-foreground leading-relaxed">The Magnus formula gives an accurate approximation of dew point from temperature and relative humidity. It uses two empirical constants (a = 17.27, b = 237.7) derived from fitting to experimental data over a wide temperature range.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>alpha = (a x T / (b + T)) + ln(RH / 100)</p>
            <p>Dew Point (Td) = (b x alpha) / (a - alpha)</p>
            <p className="text-xs text-muted-foreground mt-2">T = air temperature (C) - RH = relative humidity (%) - a = 17.27 - b = 237.7</p>
            <p className="text-xs text-muted-foreground">Accuracy: about 0.4 C between 0 C and 60 C</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Air Temperature and Humidity Affect the Dew Point</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Relative Humidity", "Dew Point (C)", "Dew Point (F)", "Comfort"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {humidityRows.map(rh => {
                  const al = (a * tempC / (b + tempC)) + Math.log(rh / 100);
                  const dp = (b * al) / (a - al);
                  const dpF = dp * 9/5 + 32;
                  const c = dp < 10 ? "Very Dry" : dp < 13 ? "Comfortable" : dp < 16 ? "Sl. Humid" : dp < 18 ? "Humid" : dp < 21 ? "Very Humid" : "Oppressive";
                  return (
                    <tr key={rh} className={`hover:bg-muted/30 ${rh === humidity ? "bg-purple-50 dark:bg-purple-950/20 font-semibold" : ""}`}>
                      <td className="py-2.5 px-4 font-semibold text-foreground">{rh}%{rh === humidity ? " (current)" : ""}</td>
                      <td className="py-2.5 px-4 text-purple-600 dark:text-purple-400 font-medium">{dp.toFixed(1)} C</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{dpF.toFixed(1)} F</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{c}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Weather Dew Point Tool for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Dew Point Range", "Comfort Level", "What It Feels Like"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {COMFORT_SCALE.map(([range, level, feels]) => (
                  <tr key={range} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground font-mono">{range}</td>
                    <td className="py-2.5 px-4 text-purple-600 dark:text-purple-400 font-bold">{level}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{feels}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/dew-point-calculator" headingLevel="h3" />
      </main>
    </>
  );
}



